"use client";
import React from 'react';

type Props = {
  onClick?: () => void;
};

export default function Logo({ onClick }: Props) {
  return (
    <a href="#hero" className="logo" onClick={onClick}>
      <div className="logo-mark" aria-hidden="true">
        <svg width="34" height="34" viewBox="0 0 34 34" fill="none" xmlns="http://www.w3.org/2000/svg">
          <rect width="34" height="34" rx="8" fill="#1F4DDB"/>
          <circle cx="17" cy="11" r="4" fill="#FBFAF6" opacity="0.9"/>
          <path d="M8 24c3-3 6-4 9-4s6 1 9 4" stroke="#FBFAF6" strokeWidth="1.2" strokeLinecap="round" strokeLinejoin="round" opacity="0.9"/>
        </svg>
      </div>
      <div className="logo-txt">
        <span className="logo-name">Oprava</span>
        <span className="logo-tag">Org Performance Intelligence</span>
      </div>
    </a>
  );
}
